async function handleChangePin(e) { e.preventDefault(); const oldPin = onlyDigits(val("oldPin")), newPin = onlyDigits(val("newPin")); if (oldPin !== String(state.currentUser.pin)) return toast("PIN เดิมไม่ถูกต้อง", "error"); if (!/^\d{4}$/.test(newPin)) return toast("PIN ใหม่ต้องเป็นตัวเลข 4 ตัว", "error"); await saveDoc("users", state.currentUser.id, { pin: newPin, requirePinChange: false, updatedAt: nowOrServer() }, true); state.currentUser.pin = newPin; state.currentUser.requirePinChange = false; await audit("change_pin", "เปลี่ยน PIN ตัวเอง"); toast("เปลี่ยน PIN สำเร็จ", "ok"); }
