async function promptEditUser(id) { const u = state.users.find(x => x.id === id); if (!u) return; if (!isOwner() && u.role !== "employee") return toast("ผู้จัดการแก้ได้เฉพาะพนักงาน", "error"); const ok = await modal("แก้ไข user / reset PIN", `<label>ชื่อ<input id="editUserName" value="${h(u.displayName)}"></label><label>บทบาท<select id="editUserRole">${isOwner()?`<option value="owner" ${u.role==="owner"?"selected":""}>เจ้าของ</option><option value="manager" ${u.role==="manager"?"selected":""}>ผู้จัดการ</option>`:""}<option value="employee" ${u.role==="employee"?"selected":""}>พนักงาน</option></select></label><label>สาขาหลัก<select id="editUserBranch">${activeBranches().map(b=>`<option value="${h(b.id)}" ${(u.branchIds||[])[0]===b.id?"selected":""}>${h(b.name)}</option>`).join("")}</select></label><label>Reset PIN<input id="editUserPin" inputmode="numeric" maxlength="4" value="${h(u.pin || "1234")}"></label>`, "บันทึก"); if (!ok) return; const role = val("editUserRole"), pin = onlyDigits(val("editUserPin")); if (!isOwner() && role !== "employee") return toast("ผู้จัดการแก้ได้เฉพาะพนักงาน", "error"); if (!/^\d{4}$/.test(pin)) return toast("PIN ต้องเป็นตัวเลข 4 ตัว", "error"); await saveDoc("users", id, { displayName: val("editUserName").trim(), role, pin, branchIds: role === "employee" ? [val("editUserBranch")] : activeBranches().map(b => b.id), requirePinChange: true, updatedAt: nowOrServer() }, true); await audit("edit_user", id); toast("บันทึก user สำเร็จ", "ok"); }
async function disableUser(id) { const u = state.users.find(x => x.id === id); if (!u || u.id === state.currentUser.id) return; if (!isOwner() && u.role !== "employee") return toast("ผู้จัดการปิดได้เฉพาะพนักงาน", "error"); if (!await confirmDialog("ปิดใช้งาน user?", `user ${u.displayName} จะ login ไม่ได้`)) return; await saveDoc("users", id, { active: false, updatedAt: nowOrServer() }, true); await audit("disable_user", u.displayName); toast("ปิดใช้งานแล้ว", "ok"); }
async function handleAddBranch(e) { e.preventDefault(); const name = val("branchName").trim(); if (!name) return toast("กรุณาใส่ชื่อสาขา", "error"); const id = makeSlugId("branch", name); await saveDoc("branches", id, { id, name, active: true, order: state.branches.length + 1, createdAt: new Date().toISOString(), updatedAt: nowOrServer() }); await audit("add_branch", name); toast("เพิ่มสาขาแล้ว", "ok"); }
async function promptRenameBranch(id) { const b = branchById(id); const name = prompt("ชื่อสาขาใหม่", b?.name || ""); if (!name) return; await saveDoc("branches", id, { name: name.trim(), updatedAt: nowOrServer() }, true); await audit("rename_branch", name); }
async function toggleBranch(id) { const b = branchById(id); await saveDoc("branches", id, { active: b.active === false, updatedAt: nowOrServer() }, true); await audit("toggle_branch", id); }
async function handleAddTea(e) { e.preventDefault(); if (!canManageTea()) return; const name = val("teaName").trim(); if (!name) return toast("กรุณาใส่ชื่อชา", "error"); const id = makeSlugId("tea", name); await saveDoc("teas", id, { id, displayName: name, active: true, order: state.teas.length + 1, sizeIds: activeSizes().map(s => s.id), createdAt: new Date().toISOString(), updatedAt: nowOrServer() }); await audit("add_tea", name); toast("เพิ่มรายการชาแล้ว", "ok"); }
async function promptRenameTea(id) { const t = teaById(id); const name = prompt("ชื่อชาใหม่", t?.displayName || ""); if (!name) return; await saveDoc("teas", id, { displayName: name.trim(), updatedAt: nowOrServer() }, true); await audit("rename_tea", name); }
async function toggleTea(id) { const t = teaById(id); await saveDoc("teas", id, { active: t.active === false, updatedAt: nowOrServer() }, true); await audit("toggle_tea", id); }
async function promptTeaSizes(id) { const t = teaById(id); if (!t) return; const html = activeSizes().map(s => `<label class="check-row"><span>${h(s.label)}</span><input type="checkbox" class="tea-size-check" value="${h(s.id)}" ${(t.sizeIds||[]).includes(s.id)?"checked":""}></label>`).join(""); const ok = await modal(`ขนาดของ ${t.displayName}`, html, "บันทึก"); if (!ok) return; const sizeIds = [...document.querySelectorAll(".tea-size-check:checked")].map(x => x.value); if (!sizeIds.length) return toast("ต้องเลือกอย่างน้อย 1 ขนาด", "error"); await saveDoc("teas", id, { sizeIds, updatedAt: nowOrServer() }, true); await audit("tea_sizes", t.displayName); }
async function handleAddSize(e) { e.preventDefault(); const grams = numberVal("sizeGrams"); if (!validPositiveInt(grams)) return toast("กรัมต้องเป็นเลขจำนวนเต็มมากกว่า 0", "error"); const id = `size_${grams}`; await saveDoc("sizes", id, { id, label: `${grams} gm`, grams, active: true, order: grams, createdAt: new Date().toISOString(), updatedAt: nowOrServer() }); await audit("add_size", `${grams} gm`); toast("เพิ่มขนาดแล้ว", "ok"); }
async function toggleSize(id) { const s = sizeById(id); await saveDoc("sizes", id, { active: s.active === false, updatedAt: nowOrServer() }, true); await audit("toggle_size", id); }
async function handleThreshold(e) { e.preventDefault(); const branchId = val("thresholdBranch"), teaId = val("thresholdTea"), sizeId = val("thresholdSize"), threshold = numberVal("thresholdQty"); if (!validNonNegativeInt(threshold)) return toast("Threshold ต้องเป็นเลข 0 ขึ้นไป", "error"); const id = stockDocId(branchId, teaId, sizeId); await saveDoc(STOCK_COLLECTION, id, { id, branchId, teaId, sizeId, qty: getStockQty(branchId, teaId, sizeId), threshold, updatedAt: nowOrServer() }, true); await audit("set_threshold", `${getBranchName(branchId)} ${getTeaName(teaId)} ${getSizeLabel(sizeId)} <= ${threshold}`); toast("บันทึกแจ้งเตือนใกล้หมดแล้ว", "ok"); }
async function handleAppearance(e) { e.preventDefault(); let logoDataUrl = state.settings.logoDataUrl || ""; const file = document.getElementById("logoFile")?.files?.[0]; if (file) logoDataUrl = await readFileAsDataURL(file); await saveSettings({ themeColor: val("themeColor"), fontScale: Number(val("fontScale")), logoDataUrl, updatedAt: nowOrServer() }); await audit("appearance", "ปรับหน้าตาระบบ"); toast("บันทึกหน้าตาแล้ว", "ok"); }
async function toggleHistoryHidden(id) { if (!isOwner()) return; const tx = state.transactions.find(t => t.id === id); if (!tx) return; await saveDoc("transactions", id, { hidden: !tx.hidden, updatedAt: nowOrServer() }, true); await audit(tx.hidden ? "unhide_history" : "hide_history", id); }
function buildBackupPayload() { return { app: "Love Matcha Stock", version: VERSION, exportedAt: new Date().toISOString(), exportedBy: state.currentUser ? { id: state.currentUser.id, displayName: state.currentUser.displayName, role: state.currentUser.role } : null, data: { users: state.users, branches: state.branches, teas: state.teas, sizes: state.sizes, stockByBranch: state.stock, transactions: state.transactions, transferRequests: state.transferRequests, settings: state.settings, auditLogs: state.auditLogs } }; }
function exportJSON() { downloadFile(`love-matcha-stock-backup-${dateStamp()}.json`, JSON.stringify(buildBackupPayload(), null, 2), "application/json"); toast("Export JSON แล้ว", "ok"); }
function exportCSV() { const rows = [["branch","tea","size","qty","threshold"]]; state.stock.forEach(s => rows.push([getBranchName(s.branchId), getTeaName(s.teaId), getSizeLabel(s.sizeId), s.qty, s.threshold || 0])); downloadFile(`love-matcha-stock-${dateStamp()}.csv`, toCSV(rows), "text/csv;charset=utf-8"); toast("Export CSV แล้ว", "ok"); }
function exportExcel() { if (!window.XLSX) return toast("ไม่พบไลบรารี Excel ให้ใช้ Export CSV แทน", "warn"); const wb = XLSX.utils.book_new(); const stockRows = state.stock.map(s => ({ สาขา: getBranchName(s.branchId), ชา: getTeaName(s.teaId), ขนาด: getSizeLabel(s.sizeId), จำนวน: Number(s.qty || 0), เตือนเมื่อเหลือไม่เกิน: Number(s.threshold || 0) })); const txRows = state.transactions.slice(0, 5000).map(tx => ({ วันที่ทำรายการ: tx.actionDate, เวลาบันทึก: tx.savedAt, สาขา: getBranchName(tx.branchId || tx.fromBranchId || tx.toBranchId), ประเภท: tx.typeLabel || TX_LABEL[tx.type] || tx.type, ชา: tx.teaName || getTeaName(tx.teaId), ขนาด: tx.sizeLabel || getSizeLabel(tx.sizeId), จำนวน: tx.qty, ก่อน: tx.beforeQty, หลัง: tx.afterQty, ผู้ทำ: tx.userName, สถานะ: tx.status, หมายเหตุ: tx.note })); XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(stockRows), "Stock"); XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(txRows), "Transactions"); XLSX.writeFile(wb, `love-matcha-stock-${dateStamp()}.xlsx`); toast("Export Excel แล้ว", "ok"); }
async function saveBackupSettings() { if (!isOwner()) return; await saveSettings({ googleScriptUrl: val("backupUrl").trim(), autoBackup: val("autoBackup"), updatedAt: nowOrServer() }); startAutoBackup(); toast("บันทึกตั้งค่า Backup แล้ว", "ok"); }
async function backupToGoogleDrive(showToast = false) { const url = state.settings.googleScriptUrl; if (!url) { if (showToast) toast("ยังไม่ได้ใส่ Google Apps Script Web App URL", "error"); return false; } try { const res = await fetch(url, { method: "POST", mode: "cors", headers: { "Content-Type": "text/plain;charset=utf-8" }, body: JSON.stringify(buildBackupPayload()) }); const text = await res.text(); let result = {}; try { result = JSON.parse(text); } catch { result = { ok: res.ok, text }; } if (!res.ok || result.ok === false) throw new Error(result.error || text || "Backup failed"); await saveSettings({ lastBackupAt: new Date().toISOString(), lastBackupStatus: "สำเร็จ", updatedAt: nowOrServer() }); if (showToast) toast("Backup ไป Google Drive สำเร็จ", "ok"); return true; } catch (err) { await saveSettings({ lastBackupAt: new Date().toISOString(), lastBackupStatus: `ล้มเหลว: ${err.message}`, updatedAt: nowOrServer() }); if (showToast) toast(`Backup ล้มเหลว: ${err.message}`, "error"); return false; } }
function startAutoBackup() { stopAutoBackup(); if (!state.currentUser || !isOwner()) return; const setting = state.settings.autoBackup || "off"; if (setting === "off" || setting === "onChange") return; const ms = setting === "30m" ? 30*60*1000 : setting === "1h" ? 60*60*1000 : 24*60*60*1000; autoBackupTimer = setInterval(() => backupToGoogleDrive(false), ms); }
function stopAutoBackup() { if (autoBackupTimer) clearInterval(autoBackupTimer); autoBackupTimer = null; }
function maybeAutoBackupOnChange() { if (isOwner() && state.settings.autoBackup === "onChange") backupToGoogleDrive(false); }
async function restoreJSON() { if (!isOwner()) return toast("Restore เฉพาะเจ้าของเท่านั้น", "error"); const file = document.getElementById("restoreFile")?.files?.[0]; if (!file) return toast("กรุณาเลือกไฟล์ JSON", "error"); const pin = prompt("ยืนยัน Restore: กรุณากรอก PIN เจ้าของ"); if (String(pin) !== String(state.currentUser.pin)) return toast("PIN ไม่ถูกต้อง", "error"); if (!await confirmDialog("ยืนยัน Restore?", "ระบบจะเขียนข้อมูลจากไฟล์เข้า Firebase/เครื่องนี้ ควร Export สำรองก่อนเสมอ")) return; const payload = JSON.parse(await file.text()); const data = payload.data || payload; await runBusy(async () => { if (state.mode === "local") { state.users = data.users || state.users; state.branches = data.branches || state.branches; state.teas = data.teas || state.teas; state.sizes = data.sizes || state.sizes; state.stock = data.stockByBranch || data.stock || state.stock; state.transactions = data.transactions || state.transactions; state.transferRequests = data.transferRequests || state.transferRequests; state.settings = { ...state.settings, ...(data.settings || {}) }; state.auditLogs = data.auditLogs || state.auditLogs; persistLocal(); render(); toast("Restore สำเร็จ", "ok"); return; } await restoreCollection("users", data.users || []); await restoreCollection("branches", data.branches || []); await restoreCollection("teas", data.teas || []); await restoreCollection("sizes", data.sizes || []); await restoreCollection(STOCK_COLLECTION, data.stockByBranch || data.stock || []); await restoreCollection("transactions", data.transactions || []); await restoreCollection("transferRequests", data.transferRequests || []); await restoreCollection("auditLogs", data.auditLogs || []); if (data.settings) await setDoc(doc(db, "settings", "global"), data.settings, { merge: true }); await audit("restore_json", file.name); toast("Restore สำเร็จ", "ok"); }); }
async function restoreCollection(col, arr) { for (const items of chunk(arr, 400)) { const batch = writeBatch(db); items.forEach(item => { const id = item.id || item.transactionId || item.transferId || makeId(col); batch.set(doc(db, col, id), { ...item, id }, { merge: true }); }); await batch.commit(); } }
async function seedFirestore() {
  if (!db) return; if (!await confirmDialog("ติดตั้งข้อมูลเริ่มต้น?", "ระบบจะสร้าง owner, สาขา, รายการชา, ขนาด และ stock ปัจจุบันจาก Excel")) return;
  await runBusy(async () => { const userSnap = await getDocs(collection(db, "users")); if (!userSnap.empty) return toast("มีข้อมูล users อยู่แล้ว ไม่ seed ซ้ำ", "warn"); const now = new Date().toISOString(); const ops = []; const owner = { id: "user_owner", displayName: "เจ้าของ", role: "owner", pin: "1234", branchIds: SEED_DATA.branches.map(b => b.id), active: true, requirePinChange: true, createdAt: now, updatedAt: now };
    ops.push(["users", owner.id, owner]); SEED_DATA.branches.forEach(b => ops.push(["branches", b.id, { ...b, createdAt: now, updatedAt: now }])); SEED_DATA.sizes.forEach(s => ops.push(["sizes", s.id, { ...s, createdAt: now, updatedAt: now }])); SEED_DATA.teas.forEach(t => ops.push(["teas", t.id, { ...t, createdAt: now, updatedAt: now }])); SEED_DATA.stock.forEach(s => { const id = stockDocId(s.branchId, s.teaId, s.sizeId); ops.push([STOCK_COLLECTION, id, { id, branchId: s.branchId, teaId: s.teaId, sizeId: s.sizeId, qty: Number(s.qty || 0), threshold: 0, updatedAt: now }]); });
    SEED_DATA.branches.forEach(branch => { const items = SEED_DATA.stock.filter(s => s.branchId === branch.id && Number(s.qty || 0) !== 0).map(s => ({ branchId: s.branchId, teaId: s.teaId, sizeId: s.sizeId, qty: Number(s.qty || 0), delta: Number(s.qty || 0), beforeQty: 0, afterQty: Number(s.qty || 0) })); ops.push(["transactions", `tx_seed_${branch.id}`, { id: `tx_seed_${branch.id}`, transactionId: `tx_seed_${branch.id}`, type: "seed_import", typeLabel: "นำเข้าจาก Excel", status: "completed", branchId: branch.id, branchName: branch.name, actionDate: todayISO(), savedAt: now, userId: "system", userName: "ระบบ", userRole: "system", note: `นำเข้า Stock ปัจจุบันจาก ${SEED_DATA.sourceWorkbook}`, hidden: false, items, createdAt: now, updatedAt: now }]); });
    ops.push(["settings", "global", defaultSettings(now)]); for (const part of chunk(ops, 430)) { const batch = writeBatch(db); part.forEach(([col, id, data]) => batch.set(doc(db, col, id), data, { merge: true })); await batch.commit(); } toast("ติดตั้งข้อมูลเริ่มต้นสำเร็จ Login ด้วย เจ้าของ / 1234", "ok"); });
}
async function saveDoc(col, id, data, merge = true) { if (!state.online) return toast("ออฟไลน์อยู่ กรุณาต่ออินเตอร์เน็ตก่อน", "error"); if (state.mode === "local") { const keyMap = { users:"users", branches:"branches", teas:"teas", sizes:"sizes", [STOCK_COLLECTION]:"stock", transactions:"transactions", transferRequests:"transferRequests", auditLogs:"auditLogs" }; const arrName = keyMap[col]; if (arrName) { const arr = state[arrName]; const idx = arr.findIndex(x => x.id === id); if (idx >= 0) arr[idx] = merge ? { ...arr[idx], ...data, id } : { ...data, id }; else arr.push({ ...data, id }); } persistLocal(); render(); return; } await setDoc(doc(db, col, id), data, { merge }); }
async function saveSettings(data) { if (state.mode === "local") { state.settings = { ...state.settings, ...data, updatedAt: new Date().toISOString() }; persistLocal(); render(); return; } await setDoc(doc(db, "settings", "global"), data, { merge: true }); }
async function audit(action, note = "") { const now = new Date().toISOString(); const item = { id: makeId("audit"), action, note, userId: state.currentUser?.id || "system", userName: state.currentUser?.displayName || "ระบบ", userRole: state.currentUser?.role || "system", createdAt: now, device: navigator.userAgent }; if (state.mode === "local") { state.auditLogs.unshift(item); persistLocal(); return; } try { await setDoc(doc(db, "auditLogs", item.id), item); } catch (err) { console.info("audit failed", err); } }
async function runBusy(fn) { if (state.busy) return; state.busy = true; render(); try { await fn(); } catch (err) { console.error(err); toast(err.message || "เกิดข้อผิดพลาด", "error"); } finally { state.busy = false; render(); } }
function activeUsers() { return state.users.filter(u => u.active !== false).sort((a,b) => String(a.displayName).localeCompare(String(b.displayName), "th")); }
function activeBranches() { return state.branches.filter(b => b.active !== false).sort((a,b) => Number(a.order || 0) - Number(b.order || 0)); }
function activeTeas() { return state.teas.filter(t => t.active !== false).sort((a,b) => Number(a.order || 0) - Number(b.order || 0)); }
function activeSizes() { return state.sizes.filter(s => s.active !== false).sort((a,b) => Number(a.order || a.grams || 0) - Number(b.order || b.grams || 0)); }
function branchById(id) { return state.branches.find(b => b.id === id); } function teaById(id) { return state.teas.find(t => t.id === id); } function sizeById(id) { return state.sizes.find(s => s.id === id); }
function getBranchName(id) { return branchById(id)?.name || id || "-"; } function getTeaName(id) { return teaById(id)?.displayName || id || "-"; } function getSizeLabel(id) { return sizeById(id)?.label || id || "-"; } function roleLabel(role) { return ROLE_LABEL[role] || role || "-"; }
function isOwner() { return state.currentUser?.role === "owner"; } function isManager() { return state.currentUser?.role === "manager"; } function canManageUsers() { return isOwner() || isManager(); } function canManageTea() { return isOwner() || isManager(); } function canManageThresholds() { return isOwner() || isManager(); } function canExportBackup() { return isOwner() || (isManager() && state.settings.managerCanExport !== false); }
function isMyBranch(branchId) { return (state.currentUser?.branchIds || []).includes(branchId); } function primaryBranchId() { return (state.currentUser?.branchIds || [])[0] || activeBranches()[0]?.id || ""; } function canAccessBranch(branchId) { return isOwner() || isManager() || isMyBranch(branchId); } function canConfirmTransfer(t) { return isOwner() || isManager() || isMyBranch(t.toBranchId); }
function sortedBranchesForUser() { const mine = new Set(state.currentUser?.branchIds || []); return activeBranches().sort((a,b) => (mine.has(a.id)?0:1) - (mine.has(b.id)?0:1) || Number(a.order||0) - Number(b.order||0)); }
function getStockQty(branchId, teaId, sizeId) { return Number(state.stock.find(s => s.branchId === branchId && s.teaId === teaId && s.sizeId === sizeId)?.qty || 0); }
function ensureLocalStock(branchId, teaId, sizeId) { const id = stockDocId(branchId, teaId, sizeId); let s = state.stock.find(x => x.id === id); if (!s) { s = { id, branchId, teaId, sizeId, qty: 0, threshold: 0, updatedAt: new Date().toISOString() }; state.stock.push(s); } return s; }
function getStockList(branchId) { const rows = [], teas = activeTeas(), sizes = activeSizes(); if (branchId === "all") { for (const tea of teas) { const allowed = tea.sizeIds || sizes.map(s=>s.id); for (const size of sizes.filter(s=>allowed.includes(s.id))) { const items = state.stock.filter(s=>s.teaId===tea.id && s.sizeId===size.id); rows.push({ teaId: tea.id, teaName: tea.displayName, sizeId: size.id, sizeLabel: size.label, qty: items.reduce((sum,s)=>sum+Number(s.qty||0),0), threshold: Math.max(0, ...items.map(s=>Number(s.threshold||0))) }); } } } else { for (const tea of teas) { const allowed = tea.sizeIds || sizes.map(s=>s.id); for (const size of sizes.filter(s=>allowed.includes(s.id))) { const d = state.stock.find(s=>s.branchId===branchId && s.teaId===tea.id && s.sizeId===size.id); rows.push({ branchId, teaId: tea.id, teaName: tea.displayName, sizeId: size.id, sizeLabel: size.label, qty: Number(d?.qty||0), threshold: Number(d?.threshold||0) }); } } } return rows; }
function aggregateTotalStock() { return getStockList("all").filter(x => Number(x.qty) !== 0).sort((a,b) => Math.abs(b.qty) - Math.abs(a.qty)); }
function lowStockItems() { return state.stock.filter(s => Number(s.threshold || 0) > 0 && Number(s.qty || 0) <= Number(s.threshold || 0)); }
function pendingTransfersForCurrentUser() { return state.transferRequests.filter(t => t.status === "pending" && canConfirmTransfer(t)); }
function filteredTransactions() { const now = new Date(); let from = "1900-01-01", to = "2999-12-31"; if (state.ui.historyRange === "today") from = to = todayISO(); else if (state.ui.historyRange === "7d") { const d = new Date(); d.setDate(d.getDate()-6); from = d.toISOString().slice(0,10); to = todayISO(); } else if (state.ui.historyRange === "month") { from = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,"0")}-01`; to = todayISO(); } else if (state.ui.historyRange === "custom") { from = state.ui.historyFrom || todayISO(); to = state.ui.historyTo || todayISO(); } const search = (state.ui.historySearch || "").toLowerCase(); return state.transactions.filter(tx => { if (!isOwner() && tx.hidden) return false; const date = String(tx.actionDate || tx.savedAt || "").slice(0,10); if (date < from || date > to) return false; const bf = state.ui.historyBranch || "all"; if (bf !== "all" && (tx.branchId || tx.fromBranchId || tx.toBranchId) !== bf) return false; if (state.ui.historyType && tx.type !== state.ui.historyType) return false; if (search) { const text = `${tx.userName||""} ${tx.teaName || getTeaName(tx.teaId)} ${tx.sizeLabel||""} ${tx.note||""} ${tx.typeLabel||""}`.toLowerCase(); if (!text.includes(search)) return false; } return true; }); }
function groupBy(arr, key) { return arr.reduce((acc,item) => ((acc[item[key]] ||= []).push(item), acc), {}); } function sortBySize(a,b) { return Number(sizeById(a.sizeId)?.grams || 0) - Number(sizeById(b.sizeId)?.grams || 0); }
function updateSizeSelectForTea(sel) { const tea = teaById(sel.value); const targetIds = String(sel.dataset.sizeTarget || "").split(",").map(x=>x.trim()).filter(Boolean); const sizes = activeSizes().filter(s => (tea?.sizeIds || []).includes(s.id)); targetIds.forEach(id => { const el = document.getElementById(id); if (el) el.innerHTML = sizes.map(s=>`<option value="${h(s.id)}">${h(s.label)}</option>`).join(""); }); }
function adjustQty(id, delta) { const input = document.getElementById(id); if (input) input.value = Math.max(0, Number(input.value || 0) + Number(delta)); }
function updateGramCheck() { const box = document.getElementById("repackGramCheck"); if (!box) return; const fromQty = numberVal("repackFromQty"), toQty = numberVal("repackToQty"), fromGram = (sizeById(val("repackFromSize"))?.grams || 0) * fromQty, toGram = (sizeById(val("repackToSize"))?.grams || 0) * toQty, diff = toGram - fromGram; box.textContent = `กรัมต้นทางประมาณ ${fmt(fromGram)}g → ปลายทาง ${fmt(toGram)}g · ส่วนต่าง ${fmt(diff)}g`; box.className = Math.abs(diff) > fromGram * .08 ? "warning-box" : "success-box"; }
function writeDisabledAttr() { return (!state.online || state.busy) ? "disabled" : ""; }
function toast(message, type = "") { const root = document.getElementById("toastRoot"); const el = document.createElement("div"); el.className = `toast ${type}`; el.textContent = message; root.appendChild(el); setTimeout(() => el.remove(), 4200); }
function modal(title, bodyHtml, okText = "ตกลง") { return new Promise(resolve => { const root = document.getElementById("modalRoot"); root.innerHTML = `<div class="modal-backdrop"><div class="modal"><h3>${h(title)}</h3><div class="stack">${bodyHtml}</div><div class="modal-actions"><button class="ghost" id="modalCancel">ยกเลิก</button><button class="primary" id="modalOk">${h(okText)}</button></div></div></div>`; document.getElementById("modalCancel").onclick = () => { root.innerHTML = ""; resolve(false); }; document.getElementById("modalOk").onclick = () => { resolve(true); setTimeout(() => root.innerHTML = "", 0); }; }); }
function confirmDialog(title, message) { return modal(title, `<p>${h(message)}</p>`, "ยืนยัน"); }
function h(value) { return String(value ?? "").replace(/[&<>"']/g, c => ({ "&":"&amp;", "<":"&lt;", ">":"&gt;", '"':"&quot;", "'":"&#39;" }[c])); }
function val(id) { return document.getElementById(id)?.value || ""; } function numberVal(id) { return Number(document.getElementById(id)?.value || 0); } function onlyDigits(s) { return String(s || "").replace(/\D/g, ""); } function validPositiveInt(n) { return Number.isInteger(Number(n)) && Number(n) > 0; } function validNonNegativeInt(n) { return Number.isInteger(Number(n)) && Number(n) >= 0; }
function fmt(n) { return new Intl.NumberFormat("th-TH").format(Number(n || 0)); } function todayISO() { return new Date().toISOString().slice(0,10); } function dateStamp() { return new Date().toISOString().replace(/[:T]/g, "-").slice(0,19); }
function formatDate(date) { if (!date) return "-"; const d = new Date(String(date).length === 10 ? `${date}T00:00:00` : date); return isNaN(d) ? h(date) : d.toLocaleDateString("th-TH", { year:"numeric", month:"short", day:"numeric" }); }
function formatDateTime(date) { if (!date) return "-"; const d = date?.toDate ? date.toDate() : new Date(date); return isNaN(d) ? h(date) : d.toLocaleString("th-TH", { dateStyle:"short", timeStyle:"short" }); }
function stockDocId(branchId, teaId, sizeId) { return `${branchId}__${teaId}__${sizeId}`; } function makeId(prefix) { return `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,9)}`; }
function makeSlugId(prefix, text) { const ascii = String(text).toLowerCase().normalize("NFKD").replace(/[^\w]+/g, "_").replace(/^_+|_+$/g, "").slice(0, 28); return `${prefix}_${ascii || Math.random().toString(36).slice(2,8)}_${Date.now().toString(36)}`; }
function nowOrServer() { return state.mode === "firebase" ? serverTimestamp() : new Date().toISOString(); } function chunk(arr, size) { const out = []; for (let i=0;i<arr.length;i+=size) out.push(arr.slice(i,i+size)); return out; }
function toCSV(rows) { return "\ufeff" + rows.map(row => row.map(cell => { const s = String(cell ?? ""); return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s; }).join(",")).join("\n"); }
function downloadFile(filename, content, mime) { const blob = new Blob([content], { type: mime }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = filename; a.click(); setTimeout(() => URL.revokeObjectURL(url), 1000); }
function readFileAsDataURL(file) { return new Promise((resolve, reject) => { const r = new FileReader(); r.onload = () => resolve(r.result); r.onerror = reject; r.readAsDataURL(file); }); }
